package com.pablo.driveflow_api.config;

import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Contact;
import io.swagger.v3.oas.models.info.Info;
import io.swagger.v3.oas.models.info.License;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class OpenApiConfig {

    @Bean
    public OpenAPI driveFlowOpenAPI() {
        return new OpenAPI()
                .info(new Info()
                        .title("DriveFlow API")
                        .version("v1.0.0")
                        .description("API para gestão de aluguel de veículos - Sistema completo de reservas e controle de frota")
                        .contact(new Contact()
                                .name("Pablo Santos")
                                .email("pablo@driveflow.com"))
                        .license(new License()
                                .name("MIT")
                                .url("https://opensource.org/licenses/MIT")));
    }
}

package com.pablo.driveflow_api.config;

import io.swagger.v3.oas.models.OpenAPI;
import io.swagger.v3.oas.models.info.Contact;
import io.swagger.v3.oas.models.info.Info;
import io.swagger.v3.oas.models.info.License;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class OpenApiConfig {

    @Bean
    public OpenAPI driveFlowOpenAPI() {
        return new OpenAPI()
                .info(new Info()
                        .title("DriveFlow API")
                        .version("v1.0.0")
                        .description("Vehicle rental management API - Complete reservation and fleet control system")
                        .contact(new Contact()
                                .name("Pablo Santos")
                                .email("pablo@driveflow.com"))
                        .license(new License()
                                .name("MIT")
                                .url("https://opensource.org/licenses/MIT")));
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.CustomerRequestDTO;
import com.pablo.driveflow_api.dto.CustomerResponseDTO;
import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.service.CustomerService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import org.springdoc.core.annotations.ParameterObject;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/customers")
@RequiredArgsConstructor
@Tag(name = "Customers", description = "Operações de gestão de clientes - CRUD completo com validação de CPF, email único e soft delete")
public class CustomerController {

    private final CustomerService customerService;

    @PostMapping
    @Operation(summary = "Criar novo cliente", description = "Cadastra um novo cliente no sistema. CPF e email devem ser únicos.")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Cliente criado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "409", description = "CPF ou email já cadastrado no sistema"),
            @ApiResponse(responseCode = "400", description = "Dados inválidos - Validação falhou")
    })
    public ResponseEntity<CustomerResponseDTO> createCustomer(@Valid @RequestBody CustomerRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(customerService.createCustomer(requestDTO));
    }

    @GetMapping
    @Operation(summary = "Listar todos os clientes", description = "Retorna uma lista paginada de todos os clientes cadastrados (excluindo deletados)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Lista de clientes recuperada com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<CustomerResponseDTO>> getAllCustomers(
            @ParameterObject Pageable pageable) {
        Page<CustomerResponseDTO> page = customerService.getAllCustomers(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Buscar cliente por ID", description = "Retorna os detalhes de um cliente específico pelo ID")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Cliente encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Cliente não encontrado")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerById(
            @Parameter(description = "ID do cliente")
            @PathVariable Long id) {
        return ResponseEntity.ok(customerService.getCustomerById(id));
    }

    @GetMapping("/cpf/{cpf}")
    @Operation(summary = "Buscar cliente por CPF", description = "Retorna os detalhes de um cliente pelo seu CPF")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Cliente encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Cliente com esse CPF não encontrado")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerByCpf(
            @Parameter(description = "CPF do cliente (11 dígitos)")
            @PathVariable String cpf) {
        return ResponseEntity.ok(customerService.getCustomerByCpf(cpf));
    }

    @GetMapping("/email/{email}")
    @Operation(summary = "Buscar cliente por email", description = "Retorna os detalhes de um cliente pelo seu email")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Cliente encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Cliente com esse email não encontrado")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerByEmail(
            @Parameter(description = "Email do cliente")
            @PathVariable String email) {
        return ResponseEntity.ok(customerService.getCustomerByEmail(email));
    }

    @PutMapping("/{id}")
    @Operation(summary = "Atualizar cliente completo", description = "Atualiza todos os dados de um cliente existente")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Cliente atualizado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Cliente não encontrado"),
            @ApiResponse(responseCode = "409", description = "CPF ou email já cadastrado em outro cliente"),
            @ApiResponse(responseCode = "400", description = "Dados inválidos - Validação falhou")
    })
    public ResponseEntity<CustomerResponseDTO> updateCustomer(
            @Parameter(description = "ID do cliente a atualizar")
            @PathVariable Long id,
            @Valid @RequestBody CustomerRequestDTO requestDTO) {
        return ResponseEntity.ok(customerService.updateCustomer(id, requestDTO));
    }

    @DeleteMapping("/{id}")
    @Operation(summary = "Deletar cliente", description = "Realiza soft delete do cliente (marca como deletado sem remover do banco)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "204", description = "Cliente deletado com sucesso"),
            @ApiResponse(responseCode = "404", description = "Cliente não encontrado")
    })
    public ResponseEntity<Void> deleteCustomer(
            @Parameter(description = "ID do cliente a deletar")
            @PathVariable Long id) {
        customerService.deleteCustomer(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping("/count/total")
    @Operation(summary = "Contar total de clientes", description = "Retorna o número total de clientes cadastrados e não deletados")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total contado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countCustomers() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", customerService.countCustomers());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.CustomerRequestDTO;
import com.pablo.driveflow_api.dto.CustomerResponseDTO;
import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.service.CustomerService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import org.springdoc.core.annotations.ParameterObject;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/customers")
@RequiredArgsConstructor
@Tag(name = "Customers", description = "Customer management operations - Complete CRUD with CPF validation, unique email and soft delete")
public class CustomerController {

    private final CustomerService customerService;

    @PostMapping
    @Operation(summary = "Create new customer", description = "Registers a new customer in the system. CPF and email must be unique.")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Customer created successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "409", description = "CPF or email already registered in the system"),
            @ApiResponse(responseCode = "400", description = "Invalid data - Validation failed")
    })
    public ResponseEntity<CustomerResponseDTO> createCustomer(@Valid @RequestBody CustomerRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(customerService.createCustomer(requestDTO));
    }

    @GetMapping
    @Operation(summary = "List all customers", description = "Returns a paginated list of all registered customers (excluding deleted)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Customer list retrieved successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<CustomerResponseDTO>> getAllCustomers(
            @ParameterObject Pageable pageable) {
        Page<CustomerResponseDTO> page = customerService.getAllCustomers(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Search customer by ID", description = "Returns the details of a specific customer by ID")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Customer found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Customer not found")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerById(
            @Parameter(description = "Customer ID")
            @PathVariable Long id) {
        return ResponseEntity.ok(customerService.getCustomerById(id));
    }

    @GetMapping("/cpf/{cpf}")
    @Operation(summary = "Search customer by CPF", description = "Returns the details of a customer by their CPF")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Customer found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Customer with this CPF not found")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerByCpf(
            @Parameter(description = "Customer CPF (11 digits)")
            @PathVariable String cpf) {
        return ResponseEntity.ok(customerService.getCustomerByCpf(cpf));
    }

    @GetMapping("/email/{email}")
    @Operation(summary = "Search customer by email", description = "Returns the details of a customer by their email")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Customer found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Customer with this email not found")
    })
    public ResponseEntity<CustomerResponseDTO> getCustomerByEmail(
            @Parameter(description = "Customer email")
            @PathVariable String email) {
        return ResponseEntity.ok(customerService.getCustomerByEmail(email));
    }

    @PutMapping("/{id}")
    @Operation(summary = "Update complete customer", description = "Updates all data of an existing customer")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Customer updated successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = CustomerResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Customer not found"),
            @ApiResponse(responseCode = "409", description = "CPF or email already registered to another customer"),
            @ApiResponse(responseCode = "400", description = "Invalid data - Validation failed")
    })
    public ResponseEntity<CustomerResponseDTO> updateCustomer(
            @Parameter(description = "Customer ID to update")
            @PathVariable Long id,
            @Valid @RequestBody CustomerRequestDTO requestDTO) {
        return ResponseEntity.ok(customerService.updateCustomer(id, requestDTO));
    }

    @DeleteMapping("/{id}")
    @Operation(summary = "Delete customer", description = "Performs soft delete of the customer (marks as deleted without removing from database)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "204", description = "Customer deleted successfully"),
            @ApiResponse(responseCode = "404", description = "Customer not found")
    })
    public ResponseEntity<Void> deleteCustomer(
            @Parameter(description = "Customer ID to delete")
            @PathVariable Long id) {
        customerService.deleteCustomer(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping("/count/total")
    @Operation(summary = "Count total customers", description = "Returns the total number of registered and non-deleted customers")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total counted successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countCustomers() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", customerService.countCustomers());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.dto.RentalRequestDTO;
import com.pablo.driveflow_api.dto.RentalResponseDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.service.RentalService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springdoc.core.annotations.ParameterObject;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.LocalDate;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/rentals")
@RequiredArgsConstructor
@Tag(name = "Rentals", description = "Operacoes de aluguel de veiculos com validacao de conflitos e calculo de valor total")
public class RentalController {

    private final RentalService rentalService;

    @PostMapping
    @Operation(summary = "Registrar aluguel", description = "Cria um novo aluguel validando conflito de periodo e disponibilidade do veiculo")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Aluguel registrado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Dados invalidos ou periodo em conflito"),
            @ApiResponse(responseCode = "404", description = "Cliente ou veiculo nao encontrado")
    })
    public ResponseEntity<RentalResponseDTO> createRental(@Valid @RequestBody RentalRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(rentalService.createRental(requestDTO));
    }

    @GetMapping
    @Operation(summary = "Listar alugueis", description = "Retorna uma lista paginada de alugueis")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Lista de alugueis recuperada",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<RentalResponseDTO>> getAllRentals(@ParameterObject Pageable pageable) {
        Page<RentalResponseDTO> page = rentalService.getAllRentals(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Buscar aluguel por ID", description = "Retorna os detalhes de um aluguel especifico")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Aluguel encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Aluguel nao encontrado")
    })
    public ResponseEntity<RentalResponseDTO> getRentalById(
            @Parameter(description = "ID do aluguel")
            @PathVariable Long id) {
        return ResponseEntity.ok(rentalService.getRentalById(id));
    }

    @GetMapping("/customer/{customerId}")
    @Operation(summary = "Historico por cliente", description = "Retorna o historico paginado de alugueis de um cliente")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Historico recuperado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class))),
            @ApiResponse(responseCode = "404", description = "Cliente nao encontrado")
    })
    public ResponseEntity<PageResponse<RentalResponseDTO>> getRentalsByCustomer(
            @Parameter(description = "ID do cliente")
            @PathVariable Long customerId,
            @ParameterObject Pageable pageable) {
        Page<RentalResponseDTO> page = rentalService.getRentalsByCustomer(customerId, pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @PatchMapping("/{id}/cancel")
    @Operation(summary = "Cancelar aluguel", description = "Cancela um aluguel ativo")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Aluguel cancelado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Aluguel ja cancelado ou finalizado"),
            @ApiResponse(responseCode = "404", description = "Aluguel nao encontrado")
    })
    public ResponseEntity<RentalResponseDTO> cancelRental(
            @Parameter(description = "ID do aluguel")
            @PathVariable Long id) {
        return ResponseEntity.ok(rentalService.cancelRental(id));
    }

    @GetMapping("/vehicles/available")
    @Operation(summary = "Veiculos disponiveis por periodo", description = "Lista os veiculos disponiveis para um periodo especifico")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Veiculos disponiveis recuperados",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class))),
            @ApiResponse(responseCode = "400", description = "Periodo invalido")
    })
    public ResponseEntity<PageResponse<VehicleResponseDTO>> getAvailableVehicles(
            @Parameter(description = "Data inicial no formato yyyy-MM-dd", example = "2026-04-15")
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate startDate,
            @Parameter(description = "Data final no formato yyyy-MM-dd", example = "2026-04-18")
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate endDate,
            @ParameterObject Pageable pageable) {
        Page<VehicleResponseDTO> page = rentalService.getAvailableVehicles(startDate, endDate, pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/count/total")
    @Operation(summary = "Contar alugueis", description = "Retorna o total de alugueis cadastrados")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total de alugueis recuperado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countRentals() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", rentalService.countRentals());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.dto.RentalRequestDTO;
import com.pablo.driveflow_api.dto.RentalResponseDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.service.RentalService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springdoc.core.annotations.ParameterObject;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.LocalDate;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/rentals")
@RequiredArgsConstructor
@Tag(name = "Rentals", description = "Vehicle rental operations with conflict validation and total value calculation")
public class RentalController {

    private final RentalService rentalService;

    @PostMapping
    @Operation(summary = "Register rental", description = "Creates a new rental validating period conflict and vehicle availability")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Rental registered successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Invalid data or conflicting period"),
            @ApiResponse(responseCode = "404", description = "Customer or vehicle not found")
    })
    public ResponseEntity<RentalResponseDTO> createRental(@Valid @RequestBody RentalRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(rentalService.createRental(requestDTO));
    }

    @GetMapping
    @Operation(summary = "List rentals", description = "Returns a paginated list of rentals")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Rental list retrieved",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<RentalResponseDTO>> getAllRentals(@ParameterObject Pageable pageable) {
        Page<RentalResponseDTO> page = rentalService.getAllRentals(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Search rental by ID", description = "Returns the details of a specific rental")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Rental found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Rental not found")
    })
    public ResponseEntity<RentalResponseDTO> getRentalById(
            @Parameter(description = "Rental ID")
            @PathVariable Long id) {
        return ResponseEntity.ok(rentalService.getRentalById(id));
    }

    @GetMapping("/customer/{customerId}")
    @Operation(summary = "Customer history", description = "Returns the paginated rental history for a customer")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "History retrieved",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class))),
            @ApiResponse(responseCode = "404", description = "Customer not found")
    })
    public ResponseEntity<PageResponse<RentalResponseDTO>> getRentalsByCustomer(
            @Parameter(description = "Customer ID")
            @PathVariable Long customerId,
            @ParameterObject Pageable pageable) {
        Page<RentalResponseDTO> page = rentalService.getRentalsByCustomer(customerId, pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @PatchMapping("/{id}/cancel")
    @Operation(summary = "Cancel rental", description = "Cancels an active rental")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Rental canceled successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = RentalResponseDTO.class))),
            @ApiResponse(responseCode = "400", description = "Rental already canceled or finished"),
            @ApiResponse(responseCode = "404", description = "Rental not found")
    })
    public ResponseEntity<RentalResponseDTO> cancelRental(
            @Parameter(description = "Rental ID")
            @PathVariable Long id) {
        return ResponseEntity.ok(rentalService.cancelRental(id));
    }

    @GetMapping("/vehicles/available")
    @Operation(summary = "Available vehicles by period", description = "Lists vehicles available for a specific period")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Available vehicles retrieved",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class))),
            @ApiResponse(responseCode = "400", description = "Invalid period")
    })
    public ResponseEntity<PageResponse<VehicleResponseDTO>> getAvailableVehicles(
            @Parameter(description = "Start date in yyyy-MM-dd format", example = "2026-04-15")
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate startDate,
            @Parameter(description = "End date in yyyy-MM-dd format", example = "2026-04-18")
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate endDate,
            @ParameterObject Pageable pageable) {
        Page<VehicleResponseDTO> page = rentalService.getAvailableVehicles(startDate, endDate, pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/count/total")
    @Operation(summary = "Count rentals", description = "Returns the total number of registered rentals")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total rentals retrieved",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countRentals() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", rentalService.countRentals());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.dto.VehicleRequestDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.model.VehicleStatus;
import com.pablo.driveflow_api.service.VehicleService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import org.springdoc.core.annotations.ParameterObject;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/vehicles")
@RequiredArgsConstructor
@Tag(name = "Vehicles", description = "Operações de gestão de veículos - CRUD completo com validação de duplicidade e controle de status")
public class VehicleController {

    private final VehicleService vehicleService;

    @PostMapping
    @Operation(summary = "Criar novo veículo", description = "Cadastra um novo veículo no sistema. A placa deve ser única.")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Veículo criado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "409", description = "Placa já cadastrada no sistema"),
            @ApiResponse(responseCode = "400", description = "Dados inválidos - Validação falhou")
    })
    public ResponseEntity<VehicleResponseDTO> createVehicle(@Valid @RequestBody VehicleRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(vehicleService.createVehicle(requestDTO));
    }

    @GetMapping
    @Operation(summary = "Listar todos os veículos", description = "Retorna uma lista paginada de todos os veículos cadastrados (excluindo deletados)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Lista de veículos recuperada com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<VehicleResponseDTO>> getAllVehicles(
            @ParameterObject Pageable pageable) {
        Page<VehicleResponseDTO> page = vehicleService.getAllVehicles(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Buscar veículo por ID", description = "Retorna os detalhes de um veículo específico pelo ID")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Veículo encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Veículo não encontrado")
    })
    public ResponseEntity<VehicleResponseDTO> getVehicleById(
            @Parameter(description = "ID do veículo")
            @PathVariable Long id) {
        return ResponseEntity.ok(vehicleService.getVehicleById(id));
    }

    @GetMapping("/plate/{plate}")
    @Operation(summary = "Buscar veículo por placa", description = "Retorna os detalhes de um veículo pela sua placa")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Veículo encontrado",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Veículo com essa placa não encontrado")
    })
    public ResponseEntity<VehicleResponseDTO> getVehicleByPlate(
            @Parameter(description = "Placa do veículo (ex: ABC1234)")
            @PathVariable String plate) {
        return ResponseEntity.ok(vehicleService.getVehicleByPlate(plate));
    }

    @PutMapping("/{id}")
    @Operation(summary = "Atualizar veículo completo", description = "Atualiza todos os dados de um veículo existente")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Veículo atualizado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Veículo não encontrado"),
            @ApiResponse(responseCode = "409", description = "Placa já cadastrada em outro veículo"),
            @ApiResponse(responseCode = "400", description = "Dados inválidos - Validação falhou")
    })
    public ResponseEntity<VehicleResponseDTO> updateVehicle(
            @Parameter(description = "ID do veículo a atualizar")
            @PathVariable Long id,
            @Valid @RequestBody VehicleRequestDTO requestDTO) {
        return ResponseEntity.ok(vehicleService.updateVehicle(id, requestDTO));
    }

    @PatchMapping("/{id}/status")
    @Operation(summary = "Atualizar status do veículo", description = "Altera apenas o status do veículo (AVAILABLE ou UNAVAILABLE)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Status atualizado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Veículo não encontrado"),
            @ApiResponse(responseCode = "400", description = "Status inválido")
    })
    public ResponseEntity<VehicleResponseDTO> updateVehicleStatus(
            @Parameter(description = "ID do veículo")
            @PathVariable Long id,
            @Parameter(description = "Novo status: AVAILABLE ou UNAVAILABLE")
            @RequestParam VehicleStatus status) {
        return ResponseEntity.ok(vehicleService.updateVehicleStatus(id, status));
    }

    @DeleteMapping("/{id}")
    @Operation(summary = "Deletar veículo", description = "Realiza soft delete do veículo (marca como deletado sem remover do banco)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "204", description = "Veículo deletado com sucesso"),
            @ApiResponse(responseCode = "404", description = "Veículo não encontrado")
    })
    public ResponseEntity<Void> deleteVehicle(
            @Parameter(description = "ID do veículo a deletar")
            @PathVariable Long id) {
        vehicleService.deleteVehicle(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping("/count/total")
    @Operation(summary = "Contar total de veículos", description = "Retorna o número total de veículos cadastrados e não deletados")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total contado com sucesso",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countVehicles() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", vehicleService.countVehicles());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.controller;

import com.pablo.driveflow_api.dto.PageResponse;
import com.pablo.driveflow_api.dto.VehicleRequestDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.model.VehicleStatus;
import com.pablo.driveflow_api.service.VehicleService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.media.Content;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;
import io.swagger.v3.oas.annotations.tags.Tag;
import org.springdoc.core.annotations.ParameterObject;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1/vehicles")
@RequiredArgsConstructor
@Tag(name = "Vehicles", description = "Vehicle management operations - Complete CRUD with duplication validation and status control")
public class VehicleController {

    private final VehicleService vehicleService;

    @PostMapping
    @Operation(summary = "Create new vehicle", description = "Registers a new vehicle in the system. Plate must be unique.")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "201", description = "Vehicle created successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "409", description = "Plate already registered in the system"),
            @ApiResponse(responseCode = "400", description = "Invalid data - Validation failed")
    })
    public ResponseEntity<VehicleResponseDTO> createVehicle(@Valid @RequestBody VehicleRequestDTO requestDTO) {
        return ResponseEntity.status(HttpStatus.CREATED).body(vehicleService.createVehicle(requestDTO));
    }

    @GetMapping
    @Operation(summary = "List all vehicles", description = "Returns a paginated list of all registered vehicles (excluding deleted)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Vehicle list retrieved successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = PageResponse.class)))
    })
    public ResponseEntity<PageResponse<VehicleResponseDTO>> getAllVehicles(
            @ParameterObject Pageable pageable) {
        Page<VehicleResponseDTO> page = vehicleService.getAllVehicles(pageable);
        return ResponseEntity.ok(PageResponse.of(
                page.getContent(),
                page.getNumber(),
                page.getSize(),
                page.getTotalPages(),
                page.getTotalElements()
        ));
    }

    @GetMapping("/{id}")
    @Operation(summary = "Search vehicle by ID", description = "Returns the details of a specific vehicle by ID")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Vehicle found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Vehicle not found")
    })
    public ResponseEntity<VehicleResponseDTO> getVehicleById(
            @Parameter(description = "Vehicle ID")
            @PathVariable Long id) {
        return ResponseEntity.ok(vehicleService.getVehicleById(id));
    }

    @GetMapping("/plate/{plate}")
    @Operation(summary = "Search vehicle by plate", description = "Returns the details of a vehicle by its plate")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Vehicle found",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Vehicle with this plate not found")
    })
    public ResponseEntity<VehicleResponseDTO> getVehicleByPlate(
            @Parameter(description = "Vehicle plate (e.g., ABC1234)")
            @PathVariable String plate) {
        return ResponseEntity.ok(vehicleService.getVehicleByPlate(plate));
    }

    @PutMapping("/{id}")
    @Operation(summary = "Update complete vehicle", description = "Updates all data of an existing vehicle")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Vehicle updated successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Vehicle not found"),
            @ApiResponse(responseCode = "409", description = "Plate already registered on another vehicle"),
            @ApiResponse(responseCode = "400", description = "Invalid data - Validation failed")
    })
    public ResponseEntity<VehicleResponseDTO> updateVehicle(
            @Parameter(description = "Vehicle ID to update")
            @PathVariable Long id,
            @Valid @RequestBody VehicleRequestDTO requestDTO) {
        return ResponseEntity.ok(vehicleService.updateVehicle(id, requestDTO));
    }

    @PatchMapping("/{id}/status")
    @Operation(summary = "Update vehicle status", description = "Changes only the vehicle status (AVAILABLE or UNAVAILABLE)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Status updated successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = VehicleResponseDTO.class))),
            @ApiResponse(responseCode = "404", description = "Vehicle not found"),
            @ApiResponse(responseCode = "400", description = "Invalid status")
    })
    public ResponseEntity<VehicleResponseDTO> updateVehicleStatus(
            @Parameter(description = "Vehicle ID")
            @PathVariable Long id,
            @Parameter(description = "New status: AVAILABLE or UNAVAILABLE")
            @RequestParam VehicleStatus status) {
        return ResponseEntity.ok(vehicleService.updateVehicleStatus(id, status));
    }

    @DeleteMapping("/{id}")
    @Operation(summary = "Delete vehicle", description = "Performs soft delete of the vehicle (marks as deleted without removing from database)")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "204", description = "Vehicle deleted successfully"),
            @ApiResponse(responseCode = "404", description = "Vehicle not found")
    })
    public ResponseEntity<Void> deleteVehicle(
            @Parameter(description = "Vehicle ID to delete")
            @PathVariable Long id) {
        vehicleService.deleteVehicle(id);
        return ResponseEntity.noContent().build();
    }

    @GetMapping("/count/total")
    @Operation(summary = "Count total vehicles", description = "Returns the total number of registered and non-deleted vehicles")
    @ApiResponses(value = {
            @ApiResponse(responseCode = "200", description = "Total counted successfully",
                    content = @Content(mediaType = "application/json", schema = @Schema(implementation = Map.class)))
    })
    public ResponseEntity<Map<String, Long>> countVehicles() {
        Map<String, Long> response = new HashMap<>();
        response.put("total", vehicleService.countVehicles());
        return ResponseEntity.ok(response);
    }
}

package com.pablo.driveflow_api.dto;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.validation.constraints.*;
import lombok.*;

import java.time.LocalDate;

@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "CustomerRequest", description = "Dados para criar ou atualizar um cliente")
public class CustomerRequestDTO {

    @NotBlank(message = "Nome do cliente não pode ser vazio")
    @Size(min = 3, max = 120, message = "Nome deve ter entre 3 e 120 caracteres")
    @Schema(example = "João Silva", description = "Nome completo do cliente")
    private String name;

    @NotBlank(message = "CPF não pode ser vazio")
    @Pattern(regexp = "^\\d{11}$", message = "CPF deve conter exatamente 11 dígitos")
    @Schema(example = "12345678901", description = "CPF do cliente (11 dígitos)")
    private String cpf;

    @NotBlank(message = "Email não pode ser vazio")
    @Email(message = "Email deve ser válido")
    @Schema(example = "joao@example.com", description = "Email único do cliente")
    private String email;

    @NotBlank(message = "Telefone não pode ser vazio")
    @Pattern(regexp = "^\\d{10,11}$", message = "Telefone deve conter 10 ou 11 dígitos")
    @Schema(example = "11987654321", description = "Telefone do cliente (10 ou 11 dígitos)")
    private String phone;

    @NotNull(message = "Data de cadastro não pode ser nula")
    @PastOrPresent(message = "Data de cadastro não pode ser no futuro")
    @Schema(example = "2024-01-15", description = "Data de cadastro do cliente")
    private LocalDate registrationDate;
}

