@RequiredArgsConstructor
@Transactional
public class CustomerService {

    private final CustomerRepository customerRepository;

    public CustomerResponseDTO createCustomer(CustomerRequestDTO requestDTO) {
        if (customerRepository.existsByCpf(requestDTO.getCpf())) {
            throw new DuplicateResourceException("Customer", "CPF", requestDTO.getCpf());
        }

        if (customerRepository.existsByEmail(requestDTO.getEmail())) {
            throw new DuplicateResourceException("Customer", "email", requestDTO.getEmail());
        }

        Customer customer = CustomerMapper.toEntity(requestDTO);
        return CustomerMapper.toDTO(customerRepository.saveAndFlush(customer));
    }

    @Transactional(readOnly = true)
    public CustomerResponseDTO getCustomerById(Long id) {
        Customer customer = customerRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "ID", id));
        return CustomerMapper.toDTO(customer);
    }

    @Transactional(readOnly = true)
    public CustomerResponseDTO getCustomerByCpf(String cpf) {
        Customer customer = customerRepository.findByCpf(cpf)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "CPF", cpf));
        return CustomerMapper.toDTO(customer);
    }

    @Transactional(readOnly = true)
    public CustomerResponseDTO getCustomerByEmail(String email) {
        Customer customer = customerRepository.findByEmail(email)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "email", email));
        return CustomerMapper.toDTO(customer);
    }

    @Transactional(readOnly = true)
    public Page<CustomerResponseDTO> getAllCustomers(Pageable pageable) {
        return customerRepository.findAll(pageable)
                .map(CustomerMapper::toDTO);
    }

    public CustomerResponseDTO updateCustomer(Long id, CustomerRequestDTO requestDTO) {
        Customer customer = customerRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "ID", id));

        if (!customer.getCpf().equals(requestDTO.getCpf()) &&
                customerRepository.existsByCpf(requestDTO.getCpf())) {
            throw new DuplicateResourceException("Customer", "CPF", requestDTO.getCpf());
        }

        if (!customer.getEmail().equals(requestDTO.getEmail()) &&
                customerRepository.existsByEmail(requestDTO.getEmail())) {
            throw new DuplicateResourceException("Customer", "email", requestDTO.getEmail());
        }

        customer.setName(requestDTO.getName());
        customer.setCpf(requestDTO.getCpf());
        customer.setEmail(requestDTO.getEmail());
        customer.setPhone(requestDTO.getPhone());
        customer.setRegistrationDate(requestDTO.getRegistrationDate());

        return CustomerMapper.toDTO(customerRepository.saveAndFlush(customer));
    }

    public void deleteCustomer(Long id) {
        Customer customer = customerRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "ID", id));

        customer.setDeletedAt(LocalDateTime.now());
        customerRepository.save(customer);
    }

    @Transactional(readOnly = true)
    public long countCustomers() {
        return customerRepository.count();
    }
}

package com.pablo.driveflow_api.service;

import com.pablo.driveflow_api.dto.RentalRequestDTO;
import com.pablo.driveflow_api.dto.RentalResponseDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.exception.DuplicateResourceException;
import com.pablo.driveflow_api.exception.ResourceNotFoundException;
import com.pablo.driveflow_api.exception.ValidationException;
import com.pablo.driveflow_api.mapper.RentalMapper;
import com.pablo.driveflow_api.mapper.VehicleMapper;
import com.pablo.driveflow_api.model.*;
import com.pablo.driveflow_api.repository.CustomerRepository;
import com.pablo.driveflow_api.repository.RentalRepository;
import com.pablo.driveflow_api.repository.VehicleRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;

@Service
@RequiredArgsConstructor
@Transactional
public class RentalService {

    private final RentalRepository rentalRepository;
    private final CustomerRepository customerRepository;
    private final VehicleRepository vehicleRepository;

    public RentalResponseDTO createRental(RentalRequestDTO requestDTO) {
        validateDates(requestDTO.getStartDate(), requestDTO.getEndDate());

        Customer customer = customerRepository.findById(requestDTO.getCustomerId())
                .orElseThrow(() -> new ResourceNotFoundException("Cliente", "ID", requestDTO.getCustomerId()));

        Vehicle vehicle = vehicleRepository.findById(requestDTO.getVehicleId())
                .orElseThrow(() -> new ResourceNotFoundException("Veiculo", "ID", requestDTO.getVehicleId()));

        if (vehicle.getStatus() != VehicleStatus.AVAILABLE) {
            throw new ValidationException("Veiculo indisponivel para aluguel");
        }

        boolean hasConflict = rentalRepository.existsConflictForVehicle(
                vehicle.getId(),
                requestDTO.getStartDate(),
                requestDTO.getEndDate(),
                RentalStatus.ACTIVE
        );

        if (hasConflict) {
            throw new DuplicateResourceException("Veiculo ja reservado para o periodo informado");
        }

        Rental rental = Rental.builder()
                .customer(customer)
                .vehicle(vehicle)
                .startDate(requestDTO.getStartDate())
                .endDate(requestDTO.getEndDate())
                .totalValue(calculateTotalValue(vehicle.getDailyValue(), requestDTO.getStartDate(), requestDTO.getEndDate()))
                .status(RentalStatus.ACTIVE)
                .build();

        return RentalMapper.toDTO(rentalRepository.saveAndFlush(rental));
    }

    @Transactional(readOnly = true)
    public RentalResponseDTO getRentalById(Long id) {
        Rental rental = rentalRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Aluguel", "ID", id));
        return RentalMapper.toDTO(rental);
    }

    @Transactional(readOnly = true)
    public Page<RentalResponseDTO> getAllRentals(Pageable pageable) {
        return rentalRepository.findAll(pageable).map(RentalMapper::toDTO);
    }

    @Transactional(readOnly = true)
    public Page<RentalResponseDTO> getRentalsByCustomer(Long customerId, Pageable pageable) {
        customerRepository.findById(customerId)
                .orElseThrow(() -> new ResourceNotFoundException("Cliente", "ID", customerId));

        return rentalRepository.findAllByCustomerId(customerId, pageable)
                .map(RentalMapper::toDTO);
    }

    public RentalResponseDTO cancelRental(Long id) {
        Rental rental = rentalRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Aluguel", "ID", id));

        if (rental.getStatus() == RentalStatus.CANCELED) {
            throw new ValidationException("Aluguel ja esta cancelado");
        }

        if (rental.getStatus() == RentalStatus.FINISHED) {
            throw new ValidationException("Aluguel finalizado nao pode ser cancelado");
        }

        rental.setStatus(RentalStatus.CANCELED);
        rental.setCanceledAt(LocalDateTime.now());

        return RentalMapper.toDTO(rentalRepository.save(rental));
    }

    @Transactional(readOnly = true)
    public Page<VehicleResponseDTO> getAvailableVehicles(LocalDate startDate, LocalDate endDate, Pageable pageable) {
        validateDates(startDate, endDate);

        return vehicleRepository.findAvailableByPeriod(
                        startDate,
                        endDate,
                        VehicleStatus.AVAILABLE,
                        RentalStatus.ACTIVE,
                        pageable
                )
                .map(VehicleMapper::toDTO);
    }

    @Transactional(readOnly = true)
    public long countRentals() {
        return rentalRepository.count();
    }

    private void validateDates(LocalDate startDate, LocalDate endDate) {
        if (startDate == null || endDate == null) {
            throw new ValidationException("Datas de inicio e fim sao obrigatorias");
        }

        if (endDate.isBefore(startDate)) {
            throw new ValidationException("Data final nao pode ser anterior a data inicial");
        }
    }

    private BigDecimal calculateTotalValue(BigDecimal dailyValue, LocalDate startDate, LocalDate endDate) {
        long days = ChronoUnit.DAYS.between(startDate, endDate) + 1;
        return dailyValue.multiply(BigDecimal.valueOf(days));
    }
}

package com.pablo.driveflow_api.service;

import com.pablo.driveflow_api.dto.RentalRequestDTO;
import com.pablo.driveflow_api.dto.RentalResponseDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.exception.DuplicateResourceException;
import com.pablo.driveflow_api.exception.ResourceNotFoundException;
import com.pablo.driveflow_api.exception.ValidationException;
import com.pablo.driveflow_api.mapper.RentalMapper;
import com.pablo.driveflow_api.mapper.VehicleMapper;
import com.pablo.driveflow_api.model.*;
import com.pablo.driveflow_api.repository.CustomerRepository;
import com.pablo.driveflow_api.repository.RentalRepository;
import com.pablo.driveflow_api.repository.VehicleRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;

@Service
@RequiredArgsConstructor
@Transactional
public class RentalService {

    private final RentalRepository rentalRepository;
    private final CustomerRepository customerRepository;
    private final VehicleRepository vehicleRepository;

    public RentalResponseDTO createRental(RentalRequestDTO requestDTO) {
        validateDates(requestDTO.getStartDate(), requestDTO.getEndDate());

        Customer customer = customerRepository.findById(requestDTO.getCustomerId())
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "ID", requestDTO.getCustomerId()));

        Vehicle vehicle = vehicleRepository.findById(requestDTO.getVehicleId())
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", requestDTO.getVehicleId()));

        if (vehicle.getStatus() != VehicleStatus.AVAILABLE) {
            throw new ValidationException("Vehicle is unavailable for rental");
        }

        boolean hasConflict = rentalRepository.existsConflictForVehicle(
                vehicle.getId(),
                requestDTO.getStartDate(),
                requestDTO.getEndDate(),
                RentalStatus.ACTIVE
        );

        if (hasConflict) {
            throw new DuplicateResourceException("Vehicle is already reserved for the requested period");
        }

        Rental rental = Rental.builder()
                .customer(customer)
                .vehicle(vehicle)
                .startDate(requestDTO.getStartDate())
                .endDate(requestDTO.getEndDate())
                .totalValue(calculateTotalValue(vehicle.getDailyValue(), requestDTO.getStartDate(), requestDTO.getEndDate()))
                .status(RentalStatus.ACTIVE)
                .build();

        return RentalMapper.toDTO(rentalRepository.saveAndFlush(rental));
    }

    @Transactional(readOnly = true)
    public RentalResponseDTO getRentalById(Long id) {
        Rental rental = rentalRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Rental", "ID", id));
        return RentalMapper.toDTO(rental);
    }

    @Transactional(readOnly = true)
    public Page<RentalResponseDTO> getAllRentals(Pageable pageable) {
        return rentalRepository.findAll(pageable).map(RentalMapper::toDTO);
    }

    @Transactional(readOnly = true)
    public Page<RentalResponseDTO> getRentalsByCustomer(Long customerId, Pageable pageable) {
        customerRepository.findById(customerId)
                .orElseThrow(() -> new ResourceNotFoundException("Customer", "ID", customerId));

        return rentalRepository.findAllByCustomerId(customerId, pageable)
                .map(RentalMapper::toDTO);
    }

    public RentalResponseDTO cancelRental(Long id) {
        Rental rental = rentalRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Rental", "ID", id));

        if (rental.getStatus() == RentalStatus.CANCELED) {
            throw new ValidationException("Rental is already canceled");
        }

        if (rental.getStatus() == RentalStatus.FINISHED) {
            throw new ValidationException("Finished rental cannot be canceled");
        }

        rental.setStatus(RentalStatus.CANCELED);
        rental.setCanceledAt(LocalDateTime.now());

        return RentalMapper.toDTO(rentalRepository.save(rental));
    }

    @Transactional(readOnly = true)
    public Page<VehicleResponseDTO> getAvailableVehicles(LocalDate startDate, LocalDate endDate, Pageable pageable) {
        validateDates(startDate, endDate);

        return vehicleRepository.findAvailableByPeriod(
                        startDate,
                        endDate,
                        VehicleStatus.AVAILABLE,
                        RentalStatus.ACTIVE,
                        pageable
                )
                .map(VehicleMapper::toDTO);
    }

    @Transactional(readOnly = true)
    public long countRentals() {
        return rentalRepository.count();
    }

    private void validateDates(LocalDate startDate, LocalDate endDate) {
        if (startDate == null || endDate == null) {
            throw new ValidationException("Start and end dates are mandatory");
        }

        if (endDate.isBefore(startDate)) {
            throw new ValidationException("End date cannot be before start date");
        }
    }

    private BigDecimal calculateTotalValue(BigDecimal dailyValue, LocalDate startDate, LocalDate endDate) {
        long days = ChronoUnit.DAYS.between(startDate, endDate) + 1;
        return dailyValue.multiply(BigDecimal.valueOf(days));
    }
}

package com.pablo.driveflow_api.service;

import com.pablo.driveflow_api.dto.VehicleRequestDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.exception.DuplicateResourceException;
import com.pablo.driveflow_api.exception.ResourceNotFoundException;
import com.pablo.driveflow_api.mapper.VehicleMapper;
import com.pablo.driveflow_api.model.Vehicle;
import com.pablo.driveflow_api.model.VehicleStatus;
import com.pablo.driveflow_api.repository.VehicleRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;

@Service
@RequiredArgsConstructor
@Transactional
public class VehicleService {

    private final VehicleRepository vehicleRepository;

    public VehicleResponseDTO createVehicle(VehicleRequestDTO requestDTO) {
        if (vehicleRepository.existsByPlate(requestDTO.getPlate())) {
            throw new DuplicateResourceException("Veículo", "placa", requestDTO.getPlate());
        }

        Vehicle vehicle = VehicleMapper.toEntity(requestDTO);
        return VehicleMapper.toDTO(vehicleRepository.saveAndFlush(vehicle));
    }

    @Transactional(readOnly = true)
    public VehicleResponseDTO getVehicleById(Long id) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Veículo", "ID", id));
        return VehicleMapper.toDTO(vehicle);
    }

    @Transactional(readOnly = true)
    public VehicleResponseDTO getVehicleByPlate(String plate) {
        Vehicle vehicle = vehicleRepository.findByPlate(plate)
                .orElseThrow(() -> new ResourceNotFoundException("Veículo", "placa", plate));
        return VehicleMapper.toDTO(vehicle);
    }

    @Transactional(readOnly = true)
    public Page<VehicleResponseDTO> getAllVehicles(Pageable pageable) {
        return vehicleRepository.findAll(pageable)
                .map(VehicleMapper::toDTO);
    }

    public VehicleResponseDTO updateVehicle(Long id, VehicleRequestDTO requestDTO) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", id));

                .orElseThrow(() -> new ResourceNotFoundException("Veículo", "ID", id));
            throw new DuplicateResourceException("Veículo", "placa", requestDTO.getPlate());
            throw new DuplicateResourceException("Vehicle", "plate", requestDTO.getPlate());
        }

        vehicle.setBrand(requestDTO.getBrand());
        vehicle.setModel(requestDTO.getModel());
        vehicle.setPlate(requestDTO.getPlate());
        vehicle.setYear(requestDTO.getYear());
        vehicle.setDailyValue(requestDTO.getDailyValue());

        return VehicleMapper.toDTO(vehicleRepository.saveAndFlush(vehicle));
    }

    public void deleteVehicle(Long id) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Veículo", "ID", id));

        vehicle.setDeletedAt(LocalDateTime.now());
        vehicleRepository.save(vehicle);
    }

    public VehicleResponseDTO updateVehicleStatus(Long id, VehicleStatus status) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Veículo", "ID", id));

        vehicle.setStatus(status);
        return VehicleMapper.toDTO(vehicleRepository.save(vehicle));
    }

    @Transactional(readOnly = true)
    public long countVehicles() {
        return vehicleRepository.count();
    }
}

package com.pablo.driveflow_api.service;

import com.pablo.driveflow_api.dto.VehicleRequestDTO;
import com.pablo.driveflow_api.dto.VehicleResponseDTO;
import com.pablo.driveflow_api.exception.DuplicateResourceException;
import com.pablo.driveflow_api.exception.ResourceNotFoundException;
import com.pablo.driveflow_api.mapper.VehicleMapper;
import com.pablo.driveflow_api.model.Vehicle;
import com.pablo.driveflow_api.model.VehicleStatus;
import com.pablo.driveflow_api.repository.VehicleRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;

@Service
@RequiredArgsConstructor
@Transactional
public class VehicleService {

    private final VehicleRepository vehicleRepository;

    public VehicleResponseDTO createVehicle(VehicleRequestDTO requestDTO) {
        if (vehicleRepository.existsByPlate(requestDTO.getPlate())) {
            throw new DuplicateResourceException("Vehicle", "plate", requestDTO.getPlate());
        }

        Vehicle vehicle = VehicleMapper.toEntity(requestDTO);
        return VehicleMapper.toDTO(vehicleRepository.saveAndFlush(vehicle));
    }

    @Transactional(readOnly = true)
    public VehicleResponseDTO getVehicleById(Long id) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", id));
        return VehicleMapper.toDTO(vehicle);
    }

    @Transactional(readOnly = true)
    public VehicleResponseDTO getVehicleByPlate(String plate) {
        Vehicle vehicle = vehicleRepository.findByPlate(plate)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "plate", plate));
        return VehicleMapper.toDTO(vehicle);
    }

    @Transactional(readOnly = true)
    public Page<VehicleResponseDTO> getAllVehicles(Pageable pageable) {
        return vehicleRepository.findAll(pageable)
                .map(VehicleMapper::toDTO);
    }

    public VehicleResponseDTO updateVehicle(Long id, VehicleRequestDTO requestDTO) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", id));

        if (!vehicle.getPlate().equals(requestDTO.getPlate()) &&
                vehicleRepository.existsByPlate(requestDTO.getPlate())) {
            throw new DuplicateResourceException("Vehicle", "plate", requestDTO.getPlate());
        }

        vehicle.setBrand(requestDTO.getBrand());
        vehicle.setModel(requestDTO.getModel());
        vehicle.setPlate(requestDTO.getPlate());
        vehicle.setYear(requestDTO.getYear());
        vehicle.setDailyValue(requestDTO.getDailyValue());

        return VehicleMapper.toDTO(vehicleRepository.saveAndFlush(vehicle));
    }

    public void deleteVehicle(Long id) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", id));

        vehicle.setDeletedAt(LocalDateTime.now());
        vehicleRepository.save(vehicle);
    }

    public VehicleResponseDTO updateVehicleStatus(Long id, VehicleStatus status) {
        Vehicle vehicle = vehicleRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Vehicle", "ID", id));

        vehicle.setStatus(status);
        return VehicleMapper.toDTO(vehicleRepository.save(vehicle));
    }

    @Transactional(readOnly = true)
    public long countVehicles() {
        return vehicleRepository.count();
    }
}
